#!/usr/bin/env node
/**
 * @hook gsd-intel-session
 * @event SessionStart
 * @matcher *
 * @description Injects codebase intelligence summary on session startup/resume.
 *   If the project has .planning/intel/summary.md (generated by /gsd:analyze-codebase),
 *   reads and outputs it as <codebase-intelligence>. This gives Claude immediate
 *   awareness of project structure, conventions, and key entities without needing
 *   to re-explore the codebase each session.
 */
const log = require('./hook-logger');
const HOOK_NAME = 'gsd-intel-session';
const EVENT_TYPE = 'SessionStart';

const fs = require('fs');
const path = require('path');

let input = '';
process.stdin.setEncoding('utf8');
process.stdin.on('data', chunk => input += chunk);
process.stdin.on('end', () => {
  try {
    const data = JSON.parse(input);
    if (!['startup', 'resume'].includes(data.source)) {
      process.exit(0);
    }

    const summaryPath = path.join(process.cwd(), '.planning', 'intel', 'summary.md');
    if (!fs.existsSync(summaryPath)) {
      log(HOOK_NAME, EVENT_TYPE, 'no intel summary found');
      process.exit(0);
    }

    const summary = fs.readFileSync(summaryPath, 'utf8').trim();
    if (summary) {
      process.stdout.write(`<codebase-intelligence>\n${summary}\n</codebase-intelligence>`);
      log(HOOK_NAME, EVENT_TYPE, 'injected codebase intelligence');
    }
    process.exit(0);
  } catch (error) {
    log(HOOK_NAME, EVENT_TYPE, `error: ${error.message}`, 'ERROR');
    process.exit(0);
  }
});
